        var extensionsPath = "/home/runner/.nuget/packages/microsoft.extensions.ai/9.10.2/lib/net9.0/Microsoft.Extensions.AI.dll";

        try
        {
            Console.WriteLine("=== LOADING ASSEMBLIES ===\n");
