            var extAsm = Assembly.LoadFrom(extensionsPath);

            Console.WriteLine($"Loaded: {agentsAsm.GetName().Name}");
            Console.WriteLine($"Loaded: {extAsm.GetName().Name}\n");

            AnalyzeAssembly(agentsAsm, "Microsoft.Agents.AI");
            AnalyzeAssembly(extAsm, "Microsoft.Extensions.AI");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"Error: {ex}");
        }
    }

    static void AnalyzeAssembly(Assembly asm, string name)
    {
        Console.WriteLine($"\n=== {name} ===\n");

        var types = asm.GetExportedTypes()
            .OrderBy(t => t.Namespace)
            .ThenBy(t => t.Name)
            .ToList();

        var namespaces = types.GroupBy(t => t.Namespace).ToList();

        foreach (var ns in namespaces)
        {
            Console.WriteLine($"Namespace: {ns.Key}");
            foreach (var type in ns)
            {
                string typeKind = type.IsInterface ? "interface" : type.IsEnum ? "enum" : type.IsValueType ? "struct" : "class";
                Console.WriteLine($"  {typeKind} {type.Name}");

                // Show important members
                var methods = type.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly)
                    .Where(m => !m.IsSpecialName && m.DeclaringType == type)
                    .OrderBy(m => m.Name)
                    .Take(3)
                    .ToList();

                foreach (var method in methods)
                {
                    var ps = string.Join(", ", method.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"));
                    Console.WriteLine($"    > {method.ReturnType.Name} {method.Name}({ps})");
                }

                var props = type.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly)
                    .Where(p => p.DeclaringType == type)
                    .Take(3)
                    .ToList();

                foreach (var prop in props)
                {
                    Console.WriteLine($"    > {prop.PropertyType.Name} {prop.Name} {{ get; {(prop.CanWrite ? "set;" : "")} }}");
                }
            }
            Console.WriteLine();
        }
    }
}
