using System.ComponentModel;
using System.Net;
using System.Text.Json;
using Microsoft.Agents.AI;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini-2024-07-18";

// --- Build the IChatClient through MEAI ---
IChatClient chatClient = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(modelId).AsIChatClient())
    .UseFunctionInvocation()
    .Build();

// --- Tools ---
var notebook = new Notebook();
var webSearch = new WebSearchTool();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearch.SearchAsync),
    AIFunctionFactory.Create(notebook.AddNote),
    AIFunctionFactory.Create(notebook.GetNotes),
};

// --- Agent ---
var agent = new ChatClientAgent(
    chatClient: chatClient,
    name: "ResearchAgent",
    instructions: """
        You are a research agent. Given a topic you must:
        1. Search the web for relevant information (perform multiple searches if needed).
        2. Take notes on the key findings using the note-taking tool.
        3. After gathering enough information, retrieve your notes and produce
           a clear, well-structured summary with references.
        Always cite the source URLs for every claim.
        """,
    tools: tools);

// --- Run ---
var topic = args.Length > 0
    ? string.Join(' ', args)
    : PromptForTopic();

Console.WriteLine($"\n🔍 Researching: {topic}\n");

var session = await agent.CreateSessionAsync();
var response = await agent.RunAsync(
    $"Research the following topic and summarize your findings:\n\n{topic}",
    session,
    new ChatClientAgentRunOptions(new ChatOptions
    {
        Temperature = 0f,
        MaxOutputTokens = 4096,
    }),
    CancellationToken.None);

Console.WriteLine("═══════════════════════════════════════");
Console.WriteLine("  RESEARCH SUMMARY");
Console.WriteLine("═══════════════════════════════════════\n");

foreach (var msg in response.Messages)
{
    if (msg.Role == ChatRole.Assistant && !string.IsNullOrWhiteSpace(msg.Text))
        Console.WriteLine(msg.Text);
}

Console.WriteLine("\n═══════════════════════════════════════");
Console.WriteLine($"  Notes collected: {notebook.NoteCount}");
Console.WriteLine("═══════════════════════════════════════");

return;

static string PromptForTopic()
{
    Console.Write("Enter a research topic: ");
    var input = Console.ReadLine()?.Trim();
    return string.IsNullOrWhiteSpace(input)
        ? throw new InvalidOperationException("A research topic is required.")
        : input;
}

// ─────────────────────────────────────────────
//  Web Search Tool
// ─────────────────────────────────────────────
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders =
        {
            { "User-Agent", "ResearchAgent/1.0" },
            { "Accept", "text/html" },
        },
        Timeout = TimeSpan.FromSeconds(15),
    };

    [Description("Searches the web for the given query and returns a list of result titles, snippets, and URLs. Use this to gather information about a topic.")]
    public async Task<string> SearchAsync(
        [Description("The search query string")] string query)
    {
        // Uses the DuckDuckGo HTML endpoint (no API key required).
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://html.duckduckgo.com/html/?q={encoded}";

        try
        {
            var html = await Http.GetStringAsync(url);
            var results = ParseDuckDuckGoResults(html);

            if (results.Count == 0)
                return $"No results found for: {query}";

            return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    private static List<SearchResult> ParseDuckDuckGoResults(string html)
    {
        var results = new List<SearchResult>();
        var span = html.AsSpan();

        // Each result lives inside a <div class="result ..."> with an <a class="result__a"> link
        // and a <a class="result__snippet"> snippet.
        const string resultMarker = "class=\"result__a\"";
        const string snippetMarker = "class=\"result__snippet\"";

        int pos = 0;
        while (results.Count < 8)
        {
            int linkStart = html.IndexOf(resultMarker, pos, StringComparison.Ordinal);
            if (linkStart < 0) break;

            var title = ExtractTagContent(html, linkStart);
            var href = ExtractHref(html, linkStart);

            int snippetStart = html.IndexOf(snippetMarker, linkStart, StringComparison.Ordinal);
            var snippet = snippetStart >= 0 ? ExtractTagContent(html, snippetStart) : "";

            pos = snippetStart >= 0 ? snippetStart + 1 : linkStart + resultMarker.Length;

            if (string.IsNullOrWhiteSpace(title)) continue;

            var decodedUrl = href.Contains("uddg=")
                ? Uri.UnescapeDataString(
                    href[(href.IndexOf("uddg=", StringComparison.Ordinal) + 5)..].Split('&')[0])
                : href;

            results.Add(new SearchResult(
                StripHtml(title).Trim(),
                StripHtml(snippet).Trim(),
                decodedUrl));
        }

        return results;
    }

    private static string ExtractHref(string html, int fromIndex)
    {
        int hrefPos = html.LastIndexOf("href=\"", fromIndex, Math.Min(fromIndex, 500), StringComparison.Ordinal);
        if (hrefPos < 0)
        {
            hrefPos = html.IndexOf("href=\"", fromIndex, StringComparison.Ordinal);
            if (hrefPos < 0) return "";
        }
        int start = hrefPos + 6;
        int end = html.IndexOf('"', start);
        return end > start ? html[start..end] : "";
    }

    private static string ExtractTagContent(string html, int fromIndex)
    {
        int tagClose = html.IndexOf('>', fromIndex);
        if (tagClose < 0) return "";
        int contentStart = tagClose + 1;
        int contentEnd = html.IndexOf('<', contentStart);
        if (contentEnd < 0) return "";
        // Grab text across nested tags
        int depth = 1;
        int i = contentStart;
        var sb = new System.Text.StringBuilder();
        while (i < html.Length && depth > 0)
        {
            if (html[i] == '<')
            {
                if (i + 1 < html.Length && html[i + 1] == '/')
                    depth--;
                else if (i + 1 < html.Length && html[i + 1] != '!')
                    depth++;
                int close = html.IndexOf('>', i);
                if (close < 0) break;
                i = close + 1;
            }
            else
            {
                sb.Append(html[i]);
                i++;
            }
        }
        return WebUtility.HtmlDecode(sb.ToString());
    }

    private static string StripHtml(string text) =>
        System.Text.RegularExpressions.Regex.Replace(text, "<[^>]+>", "");

    private record SearchResult(string Title, string Snippet, string Url);
}

// ─────────────────────────────────────────────
//  Note-Taking Tool
// ─────────────────────────────────────────────
sealed class Notebook
{
    private readonly List<Note> _notes = [];
    private int _nextId = 1;

    public int NoteCount => _notes.Count;

    [Description("Adds a research note. Use this to record important findings during research.")]
    public string AddNote(
        [Description("The content of the note")] string content,
        [Description("The source URL where this information was found")] string sourceUrl)
    {
        var note = new Note(_nextId++, content, sourceUrl);
        _notes.Add(note);
        return $"Note #{note.Id} saved.";
    }

    [Description("Retrieves all notes taken so far. Use this before writing the final summary.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
            return "No notes have been taken yet.";

        return JsonSerializer.Serialize(_notes, new JsonSerializerOptions { WriteIndented = true });
    }

    private record Note(int Id, string Content, string SourceUrl);
}

